    # Example ScoringEngine implementation
    class ScoringEngine:
        def __init__(self, criteria: Dict[str, int]):
            self.criteria = criteria

        def score_response(self, response: str, question: str) -> Dict[str, int]:
            scores = {}
            for criterion, max_score in self.criteria.items():
                # Placeholder logic: full marks if keyword present
                if criterion.lower() in response.lower():
                    scores[criterion] = max_score
                else:
                    scores[criterion] = 0
            return scores

        def calculate_total_score(self, scores: Dict[str, Dict[str, int]]) -> int:
            total_score = 0
            for question_scores in scores.values():
                total_score += sum(question_scores.values())
            return total_score

        def evaluate_candidate(self,
                               responses: Dict[str, str],
                               questions: List[str]
                              ) -> Dict[str, Dict[str, int]]:
            all_scores = {}
            for question in questions:
                if question in responses:
                    all_scores[question] = self.score_response(responses[question], question)
                else:
                    # No response: zero scores for all criteria
                    all_scores[question] = {c: 0 for c in self.criteria}
            return all_scores

    # Define scoring criteria
